#!/usr/bin/env bash
set -uo pipefail
set +H
OUTPUT="plan-27-orc-checkpoint-local-candidate-projection-v1.json"
FAILED_OUTPUT="plan-27-orc-checkpoint-local-candidate-projection-v1.failed.json"
RUN_A="/tmp/plan-27-id322-run-a.json"
RUN_B="/tmp/plan-27-id322-run-b.json"
TMP_OUTPUT="/tmp/plan-27-id322-consolidated.json"
SNAPSHOT="${PLAN27_SNAPSHOT:-${1:-local_engine_scenarios/optiplan-plan-27-engine-scenario-v1.json}}"
BUDGET='{"constructionSearchStrategy":"critical_chain_retained_alternatives","maxElapsedMs":90000,"maxExpandedPartialPlans":200,"maxGeneratedPartialPlans":600,"maxSuspendedPartialPlans":16,"initialExecutableFrontierBatchSize":4,"maxExecutableFrontierTasksScannedPerExpansion":32,"maxBranchEvaluationsPerFrontierTask":48,"maxRetainedValidBranchesPerFrontierTask":3,"maxChildrenPerDecision":3,"maxCrossCycleBacktracks":32,"initialTemporalCandidateBatchSize":8,"maxTemporalCandidatesPerAnchor":24,"maxBranchEvaluationsPerAnchor":48}'
rm -f "$RUN_A" "$RUN_B" "$TMP_OUTPUT"
trap 'rm -f "$RUN_A" "$RUN_B" "$TMP_OUTPUT"' EXIT
if [[ ! -f "$SNAPSHOT" ]]; then echo "ERROR: no existe el snapshot de Plan 27: $SNAPSHOT" >&2; exit 2; fi
npm run check || exit 1
npx tsx --test engine/orc/active/initialConstructionCausalActivationTransaction.spec.ts engine/orc/active/runInitialConstructionIterativeSession.spec.ts engine/tools/runInitialConstructionBenchmark.spec.ts || exit 1
npm test || exit 1
npx tsx engine/tools/runInitialConstructionBenchmark.ts "$SNAPSHOT" "$BUDGET" > "$RUN_A" || exit 1
npx tsx engine/tools/runInitialConstructionBenchmark.ts "$SNAPSHOT" "$BUDGET" > "$RUN_B" || exit 1
node - "$RUN_A" "$RUN_B" "$TMP_OUTPUT" <<'NODE'
const fs=require('node:fs'); const [ap,bp,out]=process.argv.slice(2); const read=p=>JSON.parse(fs.readFileSync(p,'utf8')); const a=read(ap),b=read(bp); const checks=[]; const add=(name,passed,details={})=>checks.push({name,passed:Boolean(passed),details}); const n=(r,k)=>Number(r?.[k]||0); const stableKeys=['productiveAssignmentsReached','productiveTasksRemaining','crossCycleBacktrackCount','totalExpansionWorkUnitCount','generatedAlternativeCount','causalActivationTransactionCommitCount','stopReason','finalAssignmentsFingerprint','sessionFingerprint']; for(const k of stableKeys)add(`deterministic ${k}`,a?.[k]===b?.[k],{a:a?.[k],b:b?.[k]}); add('runs non-empty',a&&b&&a.sessionFingerprint&&b.sessionFingerprint); add('stopReason is logical',a.stopReason!=='MAX_ELAPSED_MS',{stopReason:a.stopReason}); add('runtime A < 80000',n(a,'exclusiveConstructiveRuntimeMs')<80000,{runtime:a.exclusiveConstructiveRuntimeMs}); add('runtime B < 80000',n(b,'exclusiveConstructiveRuntimeMs')<80000,{runtime:b.exclusiveConstructiveRuntimeMs}); add('productiveAssignmentsReached >= 43',n(a,'productiveAssignmentsReached')>=43); add('productiveTasksRemaining <= 131',n(a,'productiveTasksRemaining')<=131); add('crossCycleBacktrackCount <= 32',n(a,'crossCycleBacktrackCount')<=32); add('commits >= 8',n(a,'causalActivationTransactionCommitCount')>=8); add('totalExpansionWorkUnitCount <= 200',n(a,'totalExpansionWorkUnitCount')<=200); add('generatedAlternativeCount <= 600',n(a,'generatedAlternativeCount')<=600); add('suspendedFrontierPeak <= 16',n(a,'suspendedFrontierPeak')<=16); add('planning VALID',a.finalCombinedValidationResult==='VALID'||a.finalValidationMatchesSelectedPartialPlan===true); add('protected intact',a.protectedAssignmentsModified===false); add('zero duplicates',Array.isArray(a.duplicateTaskIds)&&a.duplicateTaskIds.length===0); add('legacy global cursor scans = 0',n(a,'causalCheckpointLegacyGlobalCursorScanCount')===0,{actual:n(a,'causalCheckpointLegacyGlobalCursorScanCount')}); add('unexpected projection rebuilds = 0',n(a,'causalActivationCheckpointProjectionUnexpectedRebuildCount')===0,{actual:n(a,'causalActivationCheckpointProjectionUnexpectedRebuildCount')}); add('projections built inside transaction = 0',n(a,'causalActivationCheckpointProjectionBuiltInsideTransactionCount')===0,{actual:n(a,'causalActivationCheckpointProjectionBuiltInsideTransactionCount')}); add('projection reuse = transaction attempts',n(a,'causalActivationCheckpointProjectionReuseCount')===n(a,'causalActivationTransactionAttemptCount'),{reuse:n(a,'causalActivationCheckpointProjectionReuseCount'),attempts:n(a,'causalActivationTransactionAttemptCount')}); add('projection builds = transaction attempts',n(a,'causalActivationCheckpointProjectionBuildCount')===n(a,'causalActivationTransactionAttemptCount'),{builds:n(a,'causalActivationCheckpointProjectionBuildCount'),attempts:n(a,'causalActivationTransactionAttemptCount')}); add('single physical global accounting',n(a,'causalCheckpointGlobalNodeInspectionCount')===n(a,'causalActivationCheckpointProjectionGlobalSourceCount'),{cursorGlobal:n(a,'causalCheckpointGlobalNodeInspectionCount'),projectionGlobal:n(a,'causalActivationCheckpointProjectionGlobalSourceCount')}); add('subtree accounting matches projection',n(a,'causalCheckpointSubtreeNodeMatchCount')===n(a,'causalActivationCheckpointProjectionLocalCandidateCount'),{checkpoint:n(a,'causalCheckpointSubtreeNodeMatchCount'),projection:n(a,'causalActivationCheckpointProjectionLocalCandidateCount')}); add('unrelated accounting matches projection',n(a,'causalCheckpointUnrelatedNodeExcludedCount')===n(a,'causalActivationCheckpointProjectionUnrelatedExcludedCount'),{checkpoint:n(a,'causalCheckpointUnrelatedNodeExcludedCount'),projection:n(a,'causalActivationCheckpointProjectionUnrelatedExcludedCount')}); add('projection built',n(a,'causalActivationCheckpointProjectionBuildCount')>0); add('local candidates > 0',n(a,'causalActivationCheckpointProjectionLocalCandidateCount')>0); add('unrelated excluded > 0',n(a,'causalActivationCheckpointProjectionUnrelatedExcludedCount')>0); add('causal evaluations less than global sources',n(a,'causalActivationCausalEvaluationCount')<n(a,'causalActivationCheckpointProjectionGlobalSourceCount'),{evals:a.causalActivationCausalEvaluationCount,global:a.causalActivationCheckpointProjectionGlobalSourceCount}); add('not-in-subtree prepare skips = 0',n(a.causalActivationCandidateSkipReasonCounts,'CANDIDATE_NOT_IN_CHECKPOINT_SUBTREE')===0); const projectionGlobal=n(a,'causalActivationCheckpointProjectionGlobalSourceCount'); const projectionLocal=n(a,'causalActivationCheckpointProjectionLocalCandidateCount'); const projectionUnrelated=n(a,'causalActivationCheckpointProjectionUnrelatedExcludedCount'); const projectionDuplicates=n(a,'causalActivationCheckpointProjectionDuplicateCandidateCount'); const projectionFailed=n(a,'causalActivationCheckpointProjectionFailedPartialPlanExcludedCount'); const projectionInvalid=n(a,'causalActivationCheckpointProjectionInvalidSourceCandidateExcludedCount'); const projectionAccounted=n(a,'causalActivationCheckpointProjectionAccountedSourceCount'); const projectionResidual=n(a,'causalActivationCheckpointProjectionConservationResidual'); const projectionViolationCount=n(a,'causalActivationCheckpointProjectionConservationViolationCount'); const projectionSum=projectionLocal+projectionUnrelated+projectionDuplicates+projectionFailed+projectionInvalid; const projectionDetails={globalSourceCount:projectionGlobal,localCandidateCount:projectionLocal,unrelatedExcludedCount:projectionUnrelated,duplicateCandidateCount:projectionDuplicates,failedPartialPlanExcludedCount:projectionFailed,invalidSourceCandidateExcludedCount:projectionInvalid,accountedSourceCount:projectionAccounted,conservationResidual:projectionResidual,conservationViolationCount:projectionViolationCount,projectionSum}; add('projection conservation',projectionSum===projectionGlobal&&projectionAccounted===projectionGlobal&&projectionResidual===0&&projectionViolationCount===0,projectionDetails); add('projection accounted source count equals global',projectionAccounted===projectionGlobal,projectionDetails); add('projection conservation residual = 0',projectionResidual===0,projectionDetails); add('projection conservation violation count = 0',projectionViolationCount===0,projectionDetails);
for(const k of ['causalActivationBacktrackWithoutCommitCount','causalActivationCommitWithoutOpenedAttemptCount','causalActivationTransactionInvariantViolationCount','causalActivationPreparedCursorPrematureActivationCount','causalActivationCursorActivationWithoutCommitCount','causalActivationLedgerOpenAfterSourceValidationFailureCount','causalActivationArchiveCommitStateMismatchCount','activePartialPlanAlreadyExpandedAtLoopEntryCount','prematureTerminationWithEligibleSuspendedFrontierCount','causalActivationCompleteEvidenceLegacySelectorInvocationCount','causalActivationLegacyGeneratedSiblingBypassCount','causalActivationReopenCandidateBypassedTransactionCount']) add(`${k} = 0`,n(a,k)===0);
add('prepared count = commit count',n(a,'causalActivationTransactionPreparedCount')===n(a,'causalActivationTransactionCommitCount')); add('cursor activation advances = commit count',n(a,'causalActivationCursorActivationAdvanceCount')===n(a,'causalActivationTransactionCommitCount')); const samples=a.causalActivationTransactionSamples||[]; add('bounded transaction samples',samples.every(s=>(s.inspectedCandidateSamples||s.inspectedCandidates||[]).length<=10)); add('skipped samples have reasons',samples.every(s=>(s.inspectedCandidateSamples||s.inspectedCandidates||[]).every(c=>c.status!=='SKIPPED'||c.reason))); if(n(a,'causalActivationLedgerRejectedThenCommittedCount')>0)add('ledger rejected-then-committed samples coherent',(a.causalActivationLedgerRejectedThenCommittedSamples||[]).some(s=>s.committed&&s.ledgerRejectedCount>0));
const outDoc={id:322,version:'plan-27-orc-checkpoint-local-candidate-projection-v1',baselineArtifact:'plan-27-orc-causal-activation-transaction-v1.json',deterministic:checks.filter(c=>c.name.startsWith('deterministic')).every(c=>c.passed),checks,runs:[a,b],readOnly:true}; fs.writeFileSync(out,JSON.stringify(outDoc,null,2)); const failed=checks.filter(c=>!c.passed); if(failed.length){console.error(JSON.stringify(failed,null,2)); process.exit(1)}
NODE
status=$?
if [[ $status -eq 0 ]]; then mv "$TMP_OUTPUT" "$OUTPUT" && rm -f "$FAILED_OUTPUT"; else mv "$TMP_OUTPUT" "$FAILED_OUTPUT" 2>/dev/null || true; exit $status; fi
